.darma-loader-darma-custom-747 {
  color: var(--loader-color, #0ea5e9);
width: 17px;
aspect-ratio: 1;
border-radius: 50%;
background: currentColor;
display: grid;
animation: darma-loader-darma-custom-747-darma-loader-darma-custom-747-l22-0 2s infinite linear;
}
.darma-loader-darma-custom-747:before,
.darma-loader-darma-custom-747:after {
content: "";
grid-area: 1/1;
margin: 15%;
border-radius: 50%;
background: inherit;
transform: rotate(0deg) translate(150%);
animation: darma-loader-darma-custom-747-l22 1s infinite;
}
.darma-loader-darma-custom-747:after {
animation-delay: -.5s
}
@keyframes darma-loader-darma-custom-747-l22-0 {
100% {transform: rotate(1turn)}
}
@keyframes darma-loader-darma-custom-747-l22 {
100% {transform: rotate(1turn) translate(150%)}
}

